# budget_forecast.py  — predicts end-of-window budget remaining
from dataclasses import dataclass

@dataclass
class BudgetForecast:
    slo_id: str
    current_remaining: float  # fraction
    current_burn_rate: float  # multiple of nominal
    days_remaining_in_window: int

    @property
    def projected_remaining(self) -> float:
        """
        At the current burn rate, estimate budget fraction remaining
        at end of window.
        Budget consumed per day at burn_rate b:
            (b / 30) of 30-day budget per day
        So over N days: consumed = (b * N) / 30
        """
        consumed_over_remaining_days = (
            self.current_burn_rate * self.days_remaining_in_window / 30
        )
        return max(0.0, self.current_remaining - consumed_over_remaining_days)

    @property
    def freeze_risk(self) -> str:
        p = self.projected_remaining
        if p <= 0.0:
            return 'HIGH — projected exhaustion this window'
        elif p <= 0.05:
            return 'HIGH — projected hard freeze threshold breach'
        elif p <= 0.20:
            return 'MEDIUM — projected soft freeze threshold breach'
        return 'LOW — budget projected healthy at window end'

# Example: print forecasts for monthly review
if __name__ == '__main__':
    forecasts = [
        BudgetForecast('availability', 0.42, 1.3, 15),
        BudgetForecast('eval_quality', 0.28, 2.1, 15),
        BudgetForecast('safety_flag',  0.85, 0.4, 15),
    ]
    for f in forecasts:
        print(
            f'{f.slo_id}: '
            f'current={f.current_remaining:.0%}, '
            f'projected={f.projected_remaining:.0%}, '
            f'risk={f.freeze_risk}'
        )
